sql:
SELECT merchant_name 
FROM merchants 
WHERE merchant_id = 20;

SELECT *
FROM fraud_detection
WHERE result = 'suspicious';

SELECT transaction_id
FROM fraud_detection
WHERE score > (SELECT CAST(value AS REAL) FROM settings WHERE key = 'fraud_detection_threshold');

SELECT merchant_id, merchant_name
FROM merchants
WHERE state = 'WA';

SELECT COUNT(*)
FROM merchants
WHERE city = 'San Francisco';

SELECT DISTINCT m.merchant_id, m.merchant_name
FROM transactions t
INNER JOIN merchants m ON t.merchant_id = m.merchant_id;

external_knowledge:
- 'highly suspicious transactions' refers to transactions flagged as fraudulent with a high score (more than 0.8);
- 'suspects' refers to the customers involved;
- 'business where it occurred' and 'business contact details' refer to the merchant's name and contact information respectively.
